hooks.command:
python -c "
import sys, json
data = json.load(sys.stdin)
cmd = data.get('tool_input', {}).get('command', '')
protected = ['.env', 'nestflix.db', 'data/']
dangerous = ['rm ', 'rm -', 'unlink ', 'truncate ', 'del ']
for d in dangerous:
    if d in cmd:
        for p in protected:
            if p in cmd:
                print(f'BLOCKED: destructive command on protected path: {p}', file=sys.stderr)
                raise SystemExit(2)
"
